CREATE POLICY "Members can view documents" ON public.documents
  FOR SELECT USING (public.is_org_member(organization_id));
CREATE POLICY "Members can insert documents" ON public.documents
  FOR INSERT WITH CHECK (public.is_org_member(organization_id));
CREATE POLICY "Members can update documents" ON public.documents
  FOR UPDATE USING (public.is_org_member(organization_id));
CREATE POLICY "Uploaders can delete documents" ON public.documents
  FOR DELETE USING (uploaded_by = auth.uid());

-- RLS: Extraction Templates
CREATE POLICY "Members can view templates" ON public.extraction_templates
  FOR SELECT USING (public.is_org_member(organization_id));
CREATE POLICY "Members can manage templates" ON public.extraction_templates
  FOR ALL USING (public.is_org_member(organization_id));

-- RLS: Surveys
CREATE POLICY "Members can view surveys" ON public.surveys
  FOR SELECT USING (public.is_org_member(organization_id));
CREATE POLICY "Members can manage surveys" ON public.surveys
  FOR ALL USING (public.is_org_member(organization_id));

-- RLS: Survey Responses (public insert, org read)
CREATE POLICY "Anyone can submit responses" ON public.survey_responses
  FOR INSERT WITH CHECK (
    survey_id IN (SELECT id FROM public.surveys WHERE status = 'active')
  );
CREATE POLICY "Members can view responses" ON public.survey_responses
  FOR SELECT USING (
