INSERT INTO storage.buckets (id, name, public) VALUES ('documents', 'documents', false);
INSERT INTO storage.buckets (id, name, public) VALUES ('exports', 'exports', false);

-- Storage policies: org members can manage their own files
CREATE POLICY "Org members can upload documents"
  ON storage.objects FOR INSERT
  WITH CHECK (
    bucket_id = 'documents'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );

CREATE POLICY "Org members can view documents"
  ON storage.objects FOR SELECT
  USING (
    bucket_id = 'documents'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );

CREATE POLICY "Org members can delete documents"
  ON storage.objects FOR DELETE
  USING (
    bucket_id = 'documents'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );

CREATE POLICY "Org members can view exports"
  ON storage.objects FOR SELECT
  USING (
    bucket_id = 'exports'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );

CREATE POLICY "Org members can upload exports"
  ON storage.objects FOR INSERT
  WITH CHECK (
    bucket_id = 'exports'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
